2069 // Matchers for max/min idioms, eg: "select (sgt x, y), x, y" -> smax(x,y).
2070 //
2071 
2072 template <typename CmpInst_t, typename LHS_t, typename RHS_t, typename Pred_t,
2073           bool Commutable = false>
2074 struct MaxMin_match {
2075   using PredType = Pred_t;
2076   LHS_t L;
2077   RHS_t R;
2078 
2079   // The evaluation order is always stable, regardless of Commutability.
2080   // The LHS is always matched first.
2081   MaxMin_match(const LHS_t &LHS, const RHS_t &RHS) : L(LHS), R(RHS) {}
2082 
2083   template <typename OpTy> bool match(OpTy *V) {
2084     if (auto *II = dyn_cast<IntrinsicInst>(V)) {
2085       Intrinsic::ID IID = II->getIntrinsicID();
2086       if ((IID == Intrinsic::smax && Pred_t::match(ICmpInst::ICMP_SGT)) ||
2087           (IID == Intrinsic::smin && Pred_t::match(ICmpInst::ICMP_SLT)) ||
2088           (IID == Intrinsic::umax && Pred_t::match(ICmpInst::ICMP_UGT)) ||
2089           (IID == Intrinsic::umin && Pred_t::match(ICmpInst::ICMP_ULT))) {
2090         Value *LHS = II->getOperand(0), *RHS = II->getOperand(1);
2091         return (L.match(LHS) && R.match(RHS)) ||
2092                (Commutable && L.match(RHS) && R.match(LHS));
2093       }
2094     }
2095     // Look for "(x pred y) ? x : y" or "(x pred y) ? y : x".
2096     auto *SI = dyn_cast<SelectInst>(V);
2097     if (!SI)
2098       return false;
2099     auto *Cmp = dyn_cast<CmpInst_t>(SI->getCondition());
2100     if (!Cmp)
2101       return false;
2102     // At this point we have a select conditioned on a comparison.  Check that
2103     // it is the values returned by the select that are being compared.
2104     auto *TrueVal = SI->getTrueValue();
2105     auto *FalseVal = SI->getFalseValue();
2106     auto *LHS = Cmp->getOperand(0);
2107     auto *RHS = Cmp->getOperand(1);
2108     if ((TrueVal != LHS || FalseVal != RHS) &&
2109         (TrueVal != RHS || FalseVal != LHS))
2110       return false;
2111     typename CmpInst_t::Predicate Pred =
2112         LHS == TrueVal ? Cmp->getPredicate() : Cmp->getInversePredicate();
2113     // Does "(x pred y) ? x : y" represent the desired max/min operation?
2114     if (!Pred_t::match(Pred))
2115       return false;
2116     // It does!  Bind the operands.
2117     return (L.match(LHS) && R.match(RHS)) ||
2118            (Commutable && L.match(RHS) && R.match(LHS));
2119   }
2120 };
